import{_ as i,c as a,o as t,aN as e}from"./chunks/framework.CqA5BTDU.js";const r=JSON.parse('{"title":"用户与组","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/04-用户与组.md","filePath":"01.Linux基础/04-用户与组.md","lastUpdated":null}'),d={name:"01.Linux基础/04-用户与组.md"};function h(p,s,n,l,o,k){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="用户与组" tabindex="-1">用户与组 <a class="header-anchor" href="#用户与组" aria-label="Permalink to &quot;用户与组&quot;">​</a></h1><p>Linux 的登录认证、文件权限、服务进程身份都围绕用户和组展开。排查权限问题时，需要同时确认账号是否存在、属于哪些组、使用什么 Shell、以及进程以什么身份运行。</p><h2 id="一、uid-和-gid" tabindex="-1">一、UID 和 GID <a class="header-anchor" href="#一、uid-和-gid" aria-label="Permalink to &quot;一、UID 和 GID&quot;">​</a></h2><p>Linux 内核识别的是数字 ID，不是用户名。用户名只是给人看的标签，权限判断时看的是 UID 和 GID。</p><table tabindex="0"><thead><tr><th>名称</th><th>含义</th></tr></thead><tbody><tr><td>UID</td><td>用户 ID。<code>0</code> 是 root，拥有完整权限</td></tr><tr><td>GID</td><td>主组 ID。每个用户属于一个主组</td></tr><tr><td>附加组</td><td>用户额外加入的其他组，一个用户可同时属于多个组</td></tr></tbody></table><p>查看当前用户身份：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 当前用户名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # uid、gid、所有附加组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">groups</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 所属组列表</span></span></code></pre></div><p>排查权限问题看 <code>id</code> 比看 <code>whoami</code> 更有价值。一个用户能否访问某个文件，取决于他的 uid 和所有 gid，光看用户名判断不了完整权限。</p><p>文件系统中记录的 owner 和 group 本质上是 UID 和 GID 的数字。两台机器之间复制文件时，如果目标机器上相同 UID 对应的用户不同，就会出现文件属于&quot;不认识的人&quot;的情况。比如源机器上 UID 1001 是 <code>nginx</code>，目标机器上 UID 1001 是 <code>deploy</code>，文件拷过去后 <code>ls -l</code> 会显示 owner 是 <code>deploy</code>。</p><h2 id="二、用户和组的关键文件" tabindex="-1">二、用户和组的关键文件 <a class="header-anchor" href="#二、用户和组的关键文件" aria-label="Permalink to &quot;二、用户和组的关键文件&quot;">​</a></h2><p>Linux 的用户和组信息分布在几个文件中。直接 <code>cat</code> 这些文件也行，但用 <code>getent</code> 更可靠——它会走系统名称服务（NSS），LDAP、NIS 等集中认证环境也能正确查询。</p><table tabindex="0"><thead><tr><th>文件</th><th>内容</th></tr></thead><tbody><tr><td><code>/etc/passwd</code></td><td>用户名、UID、GID、家目录、Shell</td></tr><tr><td><code>/etc/shadow</code></td><td>密码哈希、密码过期策略</td></tr><tr><td><code>/etc/group</code></td><td>组名、GID、组成员</td></tr><tr><td><code>/etc/gshadow</code></td><td>组密码（很少用）</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> passwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> group</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span></span></code></pre></div><p><code>/etc/passwd</code> 一行拆解：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root:x:0:0:root:/root:/bin/bash</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>用户名</td><td><code>root</code></td><td>登录时使用的名称</td></tr><tr><td>密码占位</td><td><code>x</code></td><td>密码哈希实际存在 <code>/etc/shadow</code> 中</td></tr><tr><td>UID</td><td><code>0</code></td><td>用户 ID</td></tr><tr><td>GID</td><td><code>0</code></td><td>主组 ID</td></tr><tr><td>GECOS</td><td><code>root</code></td><td>注释字段，通常放全名或说明</td></tr><tr><td>家目录</td><td><code>/root</code></td><td>登录后的起始目录</td></tr><tr><td>Shell</td><td><code>/bin/bash</code></td><td>登录后启动的 Shell</td></tr></tbody></table><h2 id="三、创建用户" tabindex="-1">三、创建用户 <a class="header-anchor" href="#三、创建用户" aria-label="Permalink to &quot;三、创建用户&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 创建用户</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">passwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 设置密码</span></span></code></pre></div><p><code>useradd</code> 的默认行为受 <code>/etc/login.defs</code> 和 <code>/etc/default/useradd</code> 两个配置影响——是否创建家目录、默认 Shell、UID 范围等，不同发行版默认值不完全一样。生产上创建服务账号时，关键参数显式指定更保险。</p><p>指定家目录和 Shell：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/deploy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span></span></code></pre></div><p>创建不需要登录的服务用户（系统用户）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sbin/nologin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><p><code>-r</code> 创建系统用户，分配的 UID 通常在系统用户范围内（不同发行版范围不同）。<code>/sbin/nologin</code> 或 <code>/usr/sbin/nologin</code> 作为 Shell 时，该用户不能登录系统，但服务进程仍然可以用它运行。</p><h2 id="四、修改和删除用户" tabindex="-1">四、修改和删除用户 <a class="header-anchor" href="#四、修改和删除用户" aria-label="Permalink to &quot;四、修改和删除用户&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 追加到 wheel 附加组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 修改登录 Shell</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 锁定用户（禁止登录）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 解锁用户</span></span></code></pre></div><p><code>usermod -G</code> 的正常行为是替换所有附加组。要追加而不是替换，必须加 <code>-a</code>。这条很容易出错——把用户加到 docker 组或 sudo 组时漏了 <code>-a</code>，用户就会从原来的所有附加组中被移除。</p><p>删除用户：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">userdel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">userdel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 同时删除家目录和邮件目录</span></span></code></pre></div><p>正式环境下删除用户前，通常先锁定再看一段时间，确认没有遗留的定时任务或服务依赖这个账号。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> olduser</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> olduser</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 将账号过期时间设为 1970-01-01，立即失效</span></span></code></pre></div><h2 id="五、su-和-sudo" tabindex="-1">五、su 和 sudo <a class="header-anchor" href="#五、su-和-sudo" aria-label="Permalink to &quot;五、su 和 sudo&quot;">​</a></h2><p><code>su</code> 切换用户身份：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">su</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><p><code>su -</code>（带横杠）会加载目标用户的完整登录环境，包括环境变量、PATH、工作目录等。<code>su app</code> 不带横杠只切换用户身份，不切换环境，执行时会继承原来用户的 PATH 和当前目录。</p><p><code>sudo</code> 以其他用户身份执行单条命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><p>sudo 的配置文件通过 <code>visudo</code> 编辑：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">visudo</span></span></code></pre></div><p><code>visudo</code> 在保存前会检查语法，防止写错后 sudo 全部不可用。直接手动编辑 <code>/etc/sudoers</code> 有风险。</p><p>RHEL 系的管理员组通常叫 <code>wheel</code>，Ubuntu 叫 <code>sudo</code>。把一个用户加入管理员组：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Ubuntu / Debian</span></span></code></pre></div><p>sudoers 中针对特定命令的授权写法：</p><div class="language-sudoers vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sudoers</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>deploy ALL=(root) /usr/bin/systemctl restart nginx</span></span></code></pre></div><p>字段从左到右：（1）授权哪个用户或组（组前面加 <code>%</code>）；（2）从哪些主机登录时生效；（3）以谁的身份执行；（4）允许执行的具体命令，须写绝对路径。</p><p>sudo 权限的粒度越细越好。所有人配成 <code>ALL=(ALL) NOPASSWD:ALL</code> 在运维上风险偏高——事后看 sudo 日志，无法区分是谁执行了高危命令。</p><h2 id="六、查看登录状态" tabindex="-1">六、查看登录状态 <a class="header-anchor" href="#六、查看登录状态" aria-label="Permalink to &quot;六、查看登录状态&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">w</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 当前有哪些用户登录，在做什么</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">who</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 简化的在线用户列表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">last</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 历史登录记录（读取 /var/log/wtmp）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lastb</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 失败登录记录（读取 /var/log/btmp）</span></span></code></pre></div><p>SSH 暴露在公网时 <code>lastb</code> 的输出通常很长。暴力尝试多的时候，改端口只能减少日志噪音，真正的安全依赖仍然是密钥认证、限制来源 IP 或走堡垒机统一入口。</p>`,49)])])}const g=i(d,[["render",h]]);export{r as __pageData,g as default};
